import { useState, useEffect } from "react";
import "./Dashboard.css";

/* ── Mini spark bar ── */
function SparkBar({ values, color }) {
  const max = Math.max(...values);
  return (
    <div className="spark-bar">
      {values.map((v, i) => (
        <div
          key={i}
          className="spark-col"
          style={{ height: `${(v / max) * 100}%`, background: color }}
        />
      ))}
    </div>
  );
}

/* ── Score ring ── */
function ScoreRing({ score, size = 80, label, color }) {
  const r = (size - 10) / 2;
  const circ = 2 * Math.PI * r;
  const fill = (score / 100) * circ;
  return (
    <div className="score-ring-wrap" style={{ width: size, height: size }}>
      <svg width={size} height={size}>
        <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="5" />
        <circle
          cx={size / 2} cy={size / 2} r={r}
          fill="none"
          stroke={color}
          strokeWidth="5"
          strokeDasharray={`${fill} ${circ}`}
          strokeLinecap="round"
        />
      </svg>
      <div className="score-ring-label">
        <span style={{ fontSize: size * 0.22, fontFamily: "var(--font-mono)", fontWeight: 500, color }}>
          {score}%
        </span>
        {label && <span style={{ fontSize: 9, color: "var(--text-tertiary)", letterSpacing: "0.04em" }}>{label}</span>}
      </div>
    </div>
  );
}

const STAT_CARDS = [
  {
    label: "Docs Processed Today",
    value: "4,271",
    delta: "+12.4%",
    deltaDir: "up",
    sub: "vs yesterday",
    spark: [38, 52, 45, 67, 71, 59, 82, 91, 74, 85, 92, 88],
    sparkColor: "var(--accent-cyan)",
    icon: "◈",
  },
  {
    label: "Fraud Flags Raised",
    value: "38",
    delta: "-6.2%",
    deltaDir: "down-good",
    sub: "vs yesterday",
    spark: [12, 18, 14, 22, 19, 28, 21, 15, 17, 12, 9, 8],
    sparkColor: "var(--accent-amber)",
    icon: "◉",
  },
  {
    label: "Avg. Processing Time",
    value: "183ms",
    delta: "-8ms",
    deltaDir: "down-good",
    sub: "P95 latency",
    spark: [220, 210, 198, 205, 195, 191, 188, 185, 184, 186, 183, 182],
    sparkColor: "var(--accent-green)",
    icon: "◷",
  },
  {
    label: "Signature Rejections",
    value: "127",
    delta: "+3.1%",
    deltaDir: "up-bad",
    sub: "forgery suspects",
    spark: [90, 102, 95, 111, 108, 115, 119, 122, 118, 124, 126, 127],
    sparkColor: "var(--accent-red)",
    icon: "◎",
  },
];

const RECENT_DOCS = [
  { id: "CHQ-2041", type: "Cheque",  bank: "HDFC Bank",   amount: "₹2,40,000", risk: 92, status: "approved",  time: "2m ago" },
  { id: "INV-0931", type: "Invoice", bank: "ICICI Bank",  amount: "₹18,500",   risk: 34, status: "flagged",   time: "5m ago" },
  { id: "KYC-1102", type: "KYC",     bank: "Axis Bank",   amount: "—",         risk: 8,  status: "approved",  time: "9m ago" },
  { id: "CHQ-2039", type: "Cheque",  bank: "SBI",         amount: "₹85,000",   risk: 67, status: "review",    time: "12m ago" },
  { id: "LNA-0214", type: "Loan",    bank: "Kotak Bank",  amount: "₹5,00,000", risk: 21, status: "approved",  time: "16m ago" },
  { id: "CHQ-2038", type: "Cheque",  bank: "YES Bank",    amount: "₹12,000",   risk: 88, status: "rejected",  time: "23m ago" },
  { id: "INV-0930", type: "Invoice", bank: "HDFC Bank",   amount: "₹3,15,000", risk: 15, status: "approved",  time: "31m ago" },
];

const MODEL_HEALTH = [
  { name: "LayoutLM v3",         acc: 97.4, label: "Field Extraction",  color: "var(--accent-cyan)"   },
  { name: "Siamese Net v2",      acc: 94.1, label: "Signature Verify",  color: "var(--accent-purple)" },
  { name: "XGBoost Fraud",       acc: 91.8, label: "Fraud Scoring",     color: "var(--accent-amber)"  },
  { name: "BERT-FIN NER",        acc: 96.2, label: "Entity Extraction", color: "var(--accent-green)"  },
];

const SHAP_FACTORS = [
  { label: "Signature confidence",  val: -28, dir: "neg" },
  { label: "Amount field present",  val: +12, dir: "pos" },
  { label: "Date format valid",     val: +8,  dir: "pos" },
  { label: "Historical patterns",   val: -19, dir: "neg" },
  { label: "Device fingerprint",    val: +6,  dir: "pos" },
  { label: "Submission time",       val: -11, dir: "neg" },
];

function RiskBadge({ score }) {
  if (score >= 80) return <span className="badge badge-red">HIGH {score}</span>;
  if (score >= 50) return <span className="badge badge-amber">MED {score}</span>;
  return <span className="badge badge-green">LOW {score}</span>;
}

function StatusBadge({ status }) {
  const map = { approved: "badge-green", flagged: "badge-amber", review: "badge-cyan", rejected: "badge-red" };
  return <span className={`badge ${map[status] || "badge-cyan"}`}>{status.toUpperCase()}</span>;
}

export default function Dashboard({ setActivePage }) {
  const [tick, setTick] = useState(0);

  useEffect(() => {
    const id = setInterval(() => setTick(t => t + 1), 3000);
    return () => clearInterval(id);
  }, []);

  return (
    <div className="dashboard">

      {/* ── KPI Stats ── */}
      <div className="grid-4 animate-in">
        {STAT_CARDS.map((c, i) => (
          <div key={c.label} className={`card stat-card animate-in animate-in-delay-${i + 1}`}>
            <div className="stat-top">
              <span className="stat-icon">{c.icon}</span>
              <span className={`stat-delta ${c.deltaDir}`}>{c.delta}</span>
            </div>
            <div className="stat-value">{c.value}</div>
            <div className="stat-label">{c.label}</div>
            <div className="stat-sub">{c.sub}</div>
            <SparkBar values={c.spark} color={c.sparkColor} />
          </div>
        ))}
      </div>

      {/* ── Middle Row ── */}
      <div className="dash-mid-row animate-in animate-in-delay-2">
        {/* Recent Documents Table */}
        <div className="card recent-docs-card">
          <div className="card-header">
            <span className="card-title">Live Document Feed</span>
            <div style={{ display: "flex", gap: 8 }}>
              <button className="btn btn-ghost btn-sm" onClick={() => setActivePage("audit")}>
                View All
              </button>
              <button className="btn btn-primary btn-sm" onClick={() => setActivePage("upload")}>
                + Intake
              </button>
            </div>
          </div>

          <div className="table-wrapper">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Doc ID</th>
                  <th>Type</th>
                  <th>Bank</th>
                  <th>Amount</th>
                  <th>Risk Score</th>
                  <th>Status</th>
                  <th>Time</th>
                </tr>
              </thead>
              <tbody>
                {RECENT_DOCS.map(doc => (
                  <tr key={doc.id}>
                    <td><span className="mono" style={{ color: "var(--text-primary)" }}>{doc.id}</span></td>
                    <td>
                      <span className="doc-type-tag">{doc.type}</span>
                    </td>
                    <td style={{ color: "var(--text-primary)" }}>{doc.bank}</td>
                    <td className="mono">{doc.amount}</td>
                    <td><RiskBadge score={doc.risk} /></td>
                    <td><StatusBadge status={doc.status} /></td>
                    <td style={{ color: "var(--text-tertiary)", fontSize: 12 }}>{doc.time}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* SHAP Explainability */}
        <div className="card shap-card">
          <div className="card-header">
            <span className="card-title">SHAP Decision</span>
            <span className="badge badge-red">CHQ-2038 Rejected</span>
          </div>
          <p style={{ fontSize: 11, color: "var(--text-tertiary)", marginBottom: 16, lineHeight: 1.8 }}>
            Feature contributions for last flagged cheque:
          </p>
          {SHAP_FACTORS.map(f => (
            <div key={f.label} className="shap-row">
              <span className="shap-label">{f.label}</span>
              <div className="shap-bar-wrap">
                <div
                  className={`shap-bar ${f.dir}`}
                  style={{ width: `${Math.abs(f.val) * 2.2}%` }}
                />
              </div>
              <span className={`shap-val ${f.dir}`}>
                {f.dir === "pos" ? "+" : ""}{f.val}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* ── Bottom Row ── */}
      <div className="dash-bottom-row animate-in animate-in-delay-3">

        {/* Model Health */}
        <div className="card model-health-card">
          <div className="card-header">
            <span className="card-title">ML Model Accuracy</span>
            <span className="badge badge-green">All Nominal</span>
          </div>
          <div className="model-health-grid">
            {MODEL_HEALTH.map(m => (
              <div key={m.name} className="model-health-item">
                <ScoreRing score={m.acc} size={80} color={m.color} />
                <div className="model-info">
                  <span className="model-name">{m.name}</span>
                  <span className="model-sub">{m.label}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Volume breakdown */}
        <div className="card volume-card">
          <div className="card-header">
            <span className="card-title">Today's Volume by Type</span>
          </div>
          <div className="volume-list">
            {[
              { type: "Cheque",  count: 2140, pct: 50, color: "var(--accent-cyan)" },
              { type: "Invoice", count:  940, pct: 22, color: "var(--accent-purple)" },
              { type: "KYC Doc", count:  810, pct: 19, color: "var(--accent-green)" },
              { type: "Loan Agmt", count: 381, pct: 9, color: "var(--accent-amber)" },
            ].map(v => (
              <div key={v.type} className="volume-row">
                <div className="volume-meta">
                  <span className="volume-type">{v.type}</span>
                  <span className="mono volume-count">{v.count.toLocaleString()}</span>
                </div>
                <div className="progress-bar" style={{ flex: 1 }}>
                  <div
                    className="progress-fill"
                    style={{ width: `${v.pct}%`, background: v.color }}
                  />
                </div>
                <span className="volume-pct" style={{ color: v.color }}>{v.pct}%</span>
              </div>
            ))}
          </div>
        </div>

        {/* Quick Actions */}
        <div className="card quick-actions-card">
          <div className="card-header">
            <span className="card-title">Quick Actions</span>
          </div>
          <div className="quick-actions-list">
            {[
              { label: "Upload New Batch",     icon: "⊕", page: "upload",    badge: null,         color: "cyan" },
              { label: "Review Fraud Queue",   icon: "◉", page: "fraud",     badge: "5 pending",  color: "amber" },
              { label: "Verify Signatures",    icon: "◎", page: "signature", badge: "12 queued",  color: "purple" },
              { label: "Export Audit Report",  icon: "≡", page: "audit",     badge: null,         color: "green" },
            ].map(a => (
              <button
                key={a.label}
                className={`quick-action-btn qa-${a.color}`}
                onClick={() => setActivePage(a.page)}
              >
                <span className="qa-icon">{a.icon}</span>
                <span className="qa-label">{a.label}</span>
                {a.badge && <span className={`badge badge-${a.color === "amber" ? "amber" : "cyan"} qa-badge`}>{a.badge}</span>}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
